import pickle, pathlib

def save_tree(all_nodes: list[RaptorNode], path: str) -> None:
    with open(path, "wb") as f:
        pickle.dump(all_nodes, f)

def load_tree(path: str) -> list[RaptorNode] | None:
    p = pathlib.Path(path)
    if not p.exists():
        return None
    with open(p, "rb") as f:
        return pickle.load(f)

